/**
 * Geolocation helpers for middleware and edge functions.
 *
 * Reads from common CDN-injected headers:
 *  - Vercel: x-vercel-ip-country, x-vercel-ip-country-region, x-vercel-ip-city,
 *            x-vercel-ip-latitude, x-vercel-ip-longitude
 *  - Cloudflare: cf-ipcountry (country fallback only)
 */

/** Geolocation data extracted from request headers. */
export interface Geo {
  /** ISO 3166-1 alpha-2 country code, e.g. `"US"`. */
  country?: string
  /** ISO 3166-2 subdivision code, e.g. `"CA"`. */
  region?: string
  /** City name as reported by the CDN. */
  city?: string
  /** Latitude as a string, e.g. `"37.7749"`. */
  latitude?: string
  /** Longitude as a string, e.g. `"-122.4194"`. */
  longitude?: string
}

/**
 * Extracts geolocation data from the request headers.
 *
 * Vercel `x-vercel-ip-*` headers are used when present; the Cloudflare
 * `cf-ipcountry` header is used as a country-only fallback.
 *
 * @example
 * ```ts
 * import { geolocation } from 'next/geo'
 * import type { NextRequest } from 'next/server'
 *
 * export function middleware(req: NextRequest) {
 *   const { country, city } = geolocation(req)
 *   // ...
 * }
 * ```
 */
export function geolocation(request: { headers: Headers }): Geo {
  const h = request.headers
  return {
    country:
      h.get('x-vercel-ip-country') ?? h.get('cf-ipcountry') ?? undefined,
    region: h.get('x-vercel-ip-country-region') ?? undefined,
    city: h.get('x-vercel-ip-city') ?? undefined,
    latitude: h.get('x-vercel-ip-latitude') ?? undefined,
    longitude: h.get('x-vercel-ip-longitude') ?? undefined,
  }
}

/**
 * Returns the display name for an ISO 3166-1 alpha-2 country code.
 *
 * Uses the built-in `Intl.DisplayNames` API, which is available in all
 * modern edge runtimes and Node.js ≥ 12.
 *
 * @param code   ISO 3166-1 alpha-2 country code, e.g. `"US"`.
 * @param locale BCP 47 locale tag for the display language (default `"en"`).
 * @returns The localised country name, or `undefined` for an unknown code.
 *
 * @example
 * ```ts
 * countryName('US')       // → "United States"
 * countryName('DE', 'de') // → "Deutschland"
 * countryName('ZZ')       // → undefined
 * ```
 */
export function countryName(
  code: string,
  locale: string = 'en'
): string | undefined {
  try {
    return new Intl.DisplayNames([locale], { type: 'region' }).of(
      code.toUpperCase()
    )
  } catch {
    return undefined
  }
}

/**
 * Returns `true` when `geo.country` matches one of the given region codes.
 *
 * Comparison is case-insensitive. Returns `false` when `geo.country` is
 * absent.
 *
 * @param geo         Geo object, typically obtained from {@link geolocation}.
 * @param regionCodes One or more ISO 3166-1 alpha-2 country codes.
 *
 * @example
 * ```ts
 * const geo = geolocation(req)
 * if (isInRegion(geo, ['US', 'CA', 'MX'])) {
 *   // North-American visitors
 * }
 * ```
 */
export function isInRegion(
  geo: Geo,
  regionCodes: string | string[]
): boolean {
  if (!geo.country) return false
  const codes = (Array.isArray(regionCodes) ? regionCodes : [regionCodes]).map(
    (c) => c.toUpperCase()
  )
  return codes.includes(geo.country.toUpperCase())
}

/** A latitude/longitude coordinate pair. */
export interface LatLng {
  /** Latitude in decimal degrees, positive north. */
  lat: number
  /** Longitude in decimal degrees, positive east. */
  lng: number
}

/**
 * Calculates the great-circle distance between two coordinates using the
 * Haversine formula.
 *
 * @param from Origin coordinate.
 * @param to   Destination coordinate.
 * @returns Distance in kilometres.
 *
 * @example
 * ```ts
 * const { latitude, longitude } = geolocation(req)
 * const distanceKm = haversineDistance(
 *   { lat: Number(latitude), lng: Number(longitude) },
 *   { lat: 51.5074, lng: -0.1278 } // London
 * )
 * ```
 */
export function haversineDistance(from: LatLng, to: LatLng): number {
  const R = 6371 // Earth's mean radius in km
  const dLat = toRad(to.lat - from.lat)
  const dLng = toRad(to.lng - from.lng)
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(from.lat)) *
      Math.cos(toRad(to.lat)) *
      Math.sin(dLng / 2) ** 2
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
}

function toRad(deg: number): number {
  return (deg * Math.PI) / 180
}

