import {
  geolocation,
  countryName,
  isInRegion,
  haversineDistance,
} from 'next/dist/api/geo'

// ---------------------------------------------------------------------------
// geolocation()
// ---------------------------------------------------------------------------

describe('geolocation', () => {
  function makeHeaders(pairs: Record<string, string>): Headers {
    const h = new Headers()
    for (const [k, v] of Object.entries(pairs)) h.set(k, v)
    return h
  }

  it('reads all Vercel headers when present', () => {
    const headers = makeHeaders({
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'CA',
      'x-vercel-ip-city': 'San Francisco',
      'x-vercel-ip-latitude': '37.7749',
      'x-vercel-ip-longitude': '-122.4194',
    })
    expect(geolocation({ headers })).toEqual({
      country: 'US',
      region: 'CA',
      city: 'San Francisco',
      latitude: '37.7749',
      longitude: '-122.4194',
    })
  })

  it('falls back to cf-ipcountry when x-vercel-ip-country is absent', () => {
    const headers = makeHeaders({ 'cf-ipcountry': 'DE' })
    const geo = geolocation({ headers })
    expect(geo.country).toBe('DE')
  })

  it('prefers x-vercel-ip-country over cf-ipcountry', () => {
    const headers = makeHeaders({
      'x-vercel-ip-country': 'US',
      'cf-ipcountry': 'DE',
